LOAD DATA INFILE '/tmp/patients.csv' INTO TABLE patients FIELDS TERMINATED BY ',' OPTIONALLY ENCLOSED BY '"' LINES TERMINATED BY '\r\n' (id, mrn, first_name, last_name, dob, gender, contact_number, address, age, risk_score, priority, primary_doctor_id, user_id, ward_id, organization_id);
LOAD DATA INFILE '/tmp/devices.csv' INTO TABLE devices FIELDS TERMINATED BY ',' OPTIONALLY ENCLOSED BY '"' LINES TERMINATED BY '\r\n' (id, device_id, serial_number, model, firmware_version, ownership_status, device_type, status, patient_id, organization_id);
LOAD DATA INFILE '/tmp/alerts.csv' INTO TABLE alerts FIELDS TERMINATED BY ',' OPTIONALLY ENCLOSED BY '"' LINES TERMINATED BY '\r\n' (id, patient_id, device_id, alert_type, severity, severity_score, metric, value, message, ai_insight, is_acknowledged, acknowledged_by, is_resolved, resolved_by, resolved_at, resolution_notes, timestamp);
